import { VoterCardData } from "./types";
import { CANVAS_WIDTH, CANVAS_HEIGHT, POTATO_IMAGES } from "./constants";

/**
 * Loads an image with a fallback handler.
 * Returns true if loaded successfully, false otherwise.
 */
function loadImageWithFallback(
  img: HTMLImageElement,
  timeout: number = 5000
): Promise<boolean> {
  return new Promise((resolve) => {
    let loaded = false;

    const timeoutId = setTimeout(() => {
      if (!loaded) {
        resolve(false);
      }
    }, timeout);

    img.onload = () => {
      loaded = true;
      clearTimeout(timeoutId);
      resolve(true);
    };

    img.onerror = () => {
      loaded = true;
      clearTimeout(timeoutId);
      resolve(false);
    };

    // Trigger the load
    if (img.src) {
      if (img.complete) {
        loaded = true;
        clearTimeout(timeoutId);
        resolve(true);
      }
    }
  });
}

/**
 * Wraps text to fit within a maximum width
 */
function wrapText(
  ctx: CanvasRenderingContext2D,
  text: string,
  x: number,
  y: number,
  maxWidth: number,
  lineHeight: number
): number {
  const words = text.split(" ");
  let line = "";
  let currentY = y;

  for (let i = 0; i < words.length; i++) {
    const testLine = line + words[i] + " ";
    const metrics = ctx.measureText(testLine);
    const testWidth = metrics.width;

    if (testWidth > maxWidth && i > 0) {
      ctx.fillText(line, x, currentY);
      line = words[i] + " ";
      currentY += lineHeight;
    } else {
      line = testLine;
    }
  }

  ctx.fillText(line, x, currentY);
  return currentY;
}

/**
 * The core drawing engine with modern, minimal ballot card design.
 * @param canvas - The HTML5 Canvas reference
 * @param data - The state containing names, titles, and votes
 * @throws Error with user-friendly message if canvas doesn't support 2D context
 */
export async function drawCard(
  canvas: HTMLCanvasElement,
  data: VoterCardData
): Promise<void> {
  try {
    const ctx = canvas.getContext("2d");

    // Check if canvas context is available
    if (!ctx) {
      throw new Error(
        "Your browser doesn't support canvas rendering. Please use a modern browser like Chrome, Firefox, Safari, or Edge."
      );
    }

    // 1. Clear and Set Dimensions
    canvas.width = CANVAS_WIDTH;
    canvas.height = CANVAS_HEIGHT;

    // 2. White Card Container (full width, no background)
    ctx.fillStyle = "#FFFFFF";
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 3. Load Potato Asset as Watermark
    const potatoImg = new Image();
    // Convert 1-based index to 0-based array index, with bounds checking
    const arrayIndex = Math.max(
      0,
      Math.min(data.potatoIndex - 1, POTATO_IMAGES.length - 1)
    );
    potatoImg.src = POTATO_IMAGES[arrayIndex];

    const imageLoaded = await loadImageWithFallback(potatoImg);

    // Draw Potato Watermark (semi-transparent, centered, much larger)
    if (imageLoaded) {
      const potatoSize = 900;
      const potatoX = CANVAS_WIDTH / 2 - potatoSize / 2;
      const potatoY = CANVAS_HEIGHT / 2 - potatoSize / 2;

      ctx.globalAlpha = 0.08;
      ctx.drawImage(potatoImg, potatoX, potatoY, potatoSize, potatoSize);
      ctx.globalAlpha = 1.0;
    }

    // 4. "MY VOTER CARD" Label
    ctx.fillStyle = "#A1A1AA";
    ctx.font = "600 28px sans-serif";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("MY VOTER CARD", 60, 100);

    // 5. Election Title (with text wrapping)
    ctx.fillStyle = "#18181B";
    ctx.font = "bold 48px sans-serif";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    const title = data.electionTitle || "2024 Voter Guide";
    const maxTitleWidth = CANVAS_WIDTH - 120;
    let titleY = wrapText(ctx, title, 60, 160, maxTitleWidth, 60);

    // 6. Separator after title
    const separatorY = titleY + 40;
    ctx.strokeStyle = "#E4E4E7";
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(60, separatorY);
    ctx.lineTo(CANVAS_WIDTH - 60, separatorY);
    ctx.stroke();

    // Helper function to render a section of rows
    const renderRowSection = (
      title: string,
      rows: typeof data.rows,
      startY: number
    ): number => {
      if (rows.length === 0) return startY;

      // Section title
      ctx.fillStyle = "#A1A1AA";
      ctx.font = "600 24px sans-serif";
      ctx.textAlign = "left";
      ctx.textBaseline = "top";
      ctx.fillText(title, 60, startY);

      let currentY = startY + 50;
      const maxContentWidth = CANVAS_WIDTH - 120;

      for (const row of rows) {
        // Position (left-aligned, wrapped)
        ctx.fillStyle = "#52525B";
        ctx.font = "400 32px sans-serif";
        ctx.textAlign = "left";
        ctx.textBaseline = "top";
        const positionEndY = wrapText(
          ctx,
          row.position,
          60,
          currentY,
          maxContentWidth / 2 - 20,
          45
        );

        // Decision (right-aligned, wrapped)
        ctx.fillStyle = "#18181B";
        ctx.font = "600 32px sans-serif";
        ctx.textAlign = "right";
        ctx.textBaseline = "top";
        const decisionEndY = wrapText(
          ctx,
          row.decision,
          CANVAS_WIDTH - 60,
          currentY,
          maxContentWidth / 2 - 20,
          45
        );

        // Use the greater of the two heights
        currentY = Math.max(positionEndY, decisionEndY) + 20;

        // Divider line below row
        ctx.strokeStyle = "#E4E4E7";
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(60, currentY);
        ctx.lineTo(CANVAS_WIDTH - 60, currentY);
        ctx.stroke();

        currentY += 50;
      }

      return currentY;
    };

    // 7. Separate rows by type
    const filledRows = data.rows.filter(
      (r) => r.position.trim() && r.decision.trim()
    );

    const candidates = filledRows.filter((r) => r.type === "candidate");
    const measures = filledRows.filter((r) => r.type === "measure");

    // 8. Render sections
    let currentY = separatorY + 60;

    // Render candidates section
    currentY = renderRowSection("CANDIDATES", candidates, currentY);

    // Add spacing between sections if both exist
    if (candidates.length > 0 && measures.length > 0) {
      currentY += 20;
    }

    // Render measures section
    currentY = renderRowSection("MEASURES", measures, currentY);

    // 9. Footer Area - Made on www.potatovotes.com aligned to bottom of card
    ctx.fillStyle = "#A1A1AA";
    ctx.font = "400 28px sans-serif";
    ctx.textAlign = "center";
    ctx.textBaseline = "bottom";
    ctx.fillText("Made on www.potatovotes.com", CANVAS_WIDTH / 2, 1700);
  } catch (error) {
    // Re-throw with context for the component to handle
    if (error instanceof Error) {
      throw new Error(`Failed to generate card: ${error.message}`);
    }
    throw new Error("Failed to generate card: An unexpected error occurred");
  }
}
