"use client";

import React from "react";
import { Plus, X, RefreshCw } from "lucide-react";
import { VoterCardData, VotingRow } from "@/lib/types";
import {
  POTATO_IMAGES,
  MAX_NAME_CHARS,
  MAX_TITLE_CHARS,
  MAX_ROW_TEXT_CHARS,
  MAX_TOTAL_ROWS,
} from "@/lib/constants";

interface Props {
  data: VoterCardData;
  setData: React.Dispatch<React.SetStateAction<VoterCardData>>;
  onManualGenerate: () => void;
  isLoading: boolean;
  error: string | null;
}

export default function VoterCardForm({
  data,
  setData,
  onManualGenerate,
  isLoading,
  error,
}: Props) {
  const addRow = () => {
    if (data.rows.length >= MAX_TOTAL_ROWS) return;
    const newRow: VotingRow = {
      id: crypto.randomUUID(),
      type: "candidate",
      position: "",
      decision: "",
    };
    setData({ ...data, rows: [...data.rows, newRow] });
  };

  const removeRow = (id: string) => {
    setData({ ...data, rows: data.rows.filter((r) => r.id !== id) });
  };

  const updateRow = (id: string, field: keyof VotingRow, value: string) => {
    setData({
      ...data,
      rows: data.rows.map((r) =>
        r.id === id ? { ...r, [field]: value } : r
      ),
    });
  };

  const randomizePotato = () => {
    const newIndex = Math.floor(Math.random() * POTATO_IMAGES.length) + 1;
    setData({ ...data, potatoIndex: newIndex });
  };

  return (
    <section className="flex-1 space-y-6" aria-labelledby="form-title">
      <h2 id="form-title" className="sr-only">
        Voter Card Information Form
      </h2>

      {/* Error Banner */}
      {error && (
        <div
          className="bg-red-50 border-l-4 border-red-500 p-4 rounded sticky top-20 z-30"
          role="alert"
        >
          <p className="text-red-700 font-medium text-sm">{error}</p>
          <p className="text-red-600 text-xs mt-1">
            Something went wrong generating your card. Please try again.
          </p>
        </div>
      )}

      {/* Your Info */}
      <div className="bg-[#FFFCF5] p-6 rounded-xl shadow-sm border border-[#E8D5B8] space-y-4">
        <h3 className="text-xs uppercase tracking-wider text-[#8B7355] font-semibold mb-4">
          Your Info
        </h3>
        <div className="space-y-3">
          <div>
            <label htmlFor="user-name" className="sr-only">
              Your name
            </label>
            <input
              id="user-name"
              maxLength={MAX_NAME_CHARS}
              className="w-full px-3 py-2 bg-[#FDF6EC] border border-[#E8D5B8] rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-[#A68A5B] focus:border-transparent transition-colors"
              placeholder="Your name"
              value={data.name}
              onChange={(e) => setData({ ...data, name: e.target.value })}
              disabled={isLoading}
            />
            <p className="text-xs text-[#8B7355] mt-1">
              {data.name.length}/{MAX_NAME_CHARS}
            </p>
          </div>
          <div>
            <label htmlFor="election-title" className="sr-only">
              Election title
            </label>
            <input
              id="election-title"
              maxLength={MAX_TITLE_CHARS}
              className="w-full px-3 py-2 bg-[#FDF6EC] border border-[#E8D5B8] rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-[#A68A5B] focus:border-transparent transition-colors"
              placeholder="Election title (e.g. 2026 New York Primary)"
              value={data.electionTitle}
              onChange={(e) => setData({ ...data, electionTitle: e.target.value })}
              disabled={isLoading}
            />
            <p className="text-xs text-[#8B7355] mt-1">
              {data.electionTitle.length}/{MAX_TITLE_CHARS}
            </p>
          </div>
        </div>
      </div>

      {/* Voting Decisions */}
      <div className="bg-[#FFFCF5] p-6 rounded-xl shadow-sm border border-[#E8D5B8] space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-xs uppercase tracking-wider text-[#8B7355] font-semibold">
            Voting Decisions
          </h3>
          <span className="text-xs text-[#8B7355] bg-[#F5EDE0] rounded-full px-2.5 py-1 font-medium">
            {data.rows.length} {data.rows.length === 1 ? "item" : "items"}
          </span>
        </div>

        <div className="space-y-3">
          {data.rows.map((row, index) => (
            <div key={row.id} className="space-y-2">
              {index > 0 && <div className="border-t border-[#E8D5B8]" />}
              <div className="flex items-center gap-2 pt-1 flex-col sm:flex-row">
                <select
                  value={row.type}
                  onChange={(e) => updateRow(row.id, "type", e.target.value)}
                  disabled={isLoading}
                  className="text-xs bg-[#F5EDE0] text-[#3D2E16] rounded-lg px-2.5 py-1.5 border border-[#E8D5B8] focus:outline-none focus:ring-2 focus:ring-[#A68A5B] font-medium transition-colors w-full sm:w-auto"
                >
                  <option value="candidate">Candidate</option>
                  <option value="measure">Measure</option>
                </select>

                <input
                  maxLength={MAX_ROW_TEXT_CHARS}
                  placeholder={
                    row.type === "candidate"
                      ? "Position (e.g. Governor)"
                      : "Measure (e.g. Prop 1)"
                  }
                  value={row.position}
                  onChange={(e) =>
                    updateRow(row.id, "position", e.target.value)
                  }
                  disabled={isLoading}
                  className="flex-1 px-3 py-2 bg-[#FDF6EC] border border-[#E8D5B8] rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-[#A68A5B] focus:border-transparent transition-colors"
                />

                <input
                  maxLength={MAX_ROW_TEXT_CHARS}
                  placeholder={
                    row.type === "candidate" ? "Candidate name" : "Yes / No"
                  }
                  value={row.decision}
                  onChange={(e) =>
                    updateRow(row.id, "decision", e.target.value)
                  }
                  disabled={isLoading}
                  className="flex-1 px-3 py-2 bg-[#FDF6EC] border border-[#E8D5B8] rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-[#A68A5B] focus:border-transparent transition-colors"
                />

                {data.rows.length > 1 && (
                  <button
                    onClick={() => removeRow(row.id)}
                    disabled={isLoading}
                    className="p-1.5 text-[#8B7355] hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed w-full sm:w-auto"
                    aria-label={`Remove row ${index + 1}`}
                  >
                    <X className="h-4 w-4 mx-auto" />
                  </button>
                )}
              </div>
              <div className="text-xs text-[#8B7355]">
                Position: {row.position.length}/{MAX_ROW_TEXT_CHARS} | Decision:{" "}
                {row.decision.length}/{MAX_ROW_TEXT_CHARS}
              </div>
            </div>
          ))}
        </div>

        {data.rows.length < MAX_TOTAL_ROWS ? (
          <button
            onClick={addRow}
            disabled={isLoading}
            className="w-full py-2 border-2 border-dashed border-[#E8D5B8] rounded-lg text-[#8B7355] hover:border-[#A68A5B] hover:text-[#A68A5B] hover:bg-[#F5EDE0] transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed font-medium text-sm"
          >
            <Plus className="h-4 w-4" /> Add Row
          </button>
        ) : (
          <p className="text-center text-xs text-[#8B7355] py-2">
            Max limit of {MAX_TOTAL_ROWS} rows reached.
          </p>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-3">
        <button
          onClick={onManualGenerate}
          disabled={isLoading}
          className="flex-1 bg-[#A68A5B] hover:bg-[#C8973E] disabled:bg-[#8B7355] disabled:cursor-not-allowed text-white font-semibold py-3 px-6 rounded-lg shadow-md hover:shadow-lg transition-all active:scale-[0.98] disabled:active:scale-100 flex items-center justify-center gap-2"
        >
          {isLoading ? (
            <>
              <span className="inline-block animate-spin">⏳</span>
              <span className="hidden sm:inline">Generating...</span>
              <span className="sm:hidden">Gen...</span>
            </>
          ) : (
            "Generate Card"
          )}
        </button>
        <button
          onClick={randomizePotato}
          disabled={isLoading}
          className="p-3 text-[#8B7355] hover:bg-[#F5EDE0] rounded-lg transition-colors border border-[#E8D5B8] hover:border-[#A68A5B] disabled:opacity-50 disabled:cursor-not-allowed"
          aria-label="Change random potato image"
          title="Swap Potato"
        >
          <RefreshCw className="h-5 w-5" />
        </button>
      </div>
    </section>
  );
}
